"""CHARME training loop.

Source: authors' train.py from charme-rl repo.
Fixes applied:
  1. TrainConfig updated for diverse training set (195 graphs, 25 families, max n=120)
  2. training_size auto-detected from manifest.pkl written by 01_generate_training_data.py
  3. MinorEmbeddingEnv constructor updated to pass orderlist_path and atom_binary_path
  4. ppo_agent.update() called with (env) — fixed signature
  5. update_timestep changed to episode-based (update every 100 episodes per paper)
  6. sigma scheduling added (increases by 0.01 per update, per Section 3.1.2)
  7. graph_list and minorminer_list loaded from training_data/ instead of TODO comment
All other logic from authors' exact train.py preserved.

Usage:
    python train.py
    python train.py --atom_binary /path/to/atom_system --device cuda
"""

from __future__ import annotations

import argparse
import os
import copy
import pickle
from dataclasses import dataclass
from pathlib import Path

import networkx as nx
import torch

from charme.env import MinorEmbeddingEnv
from charme.ppo import PPO


@dataclass
class TrainConfig:
    # Paper-exact values from Section 4.1
    env_name: str = "CHARME"
    has_continuous_action_space: bool = False
    action_std: float = 0.6

    # Paper-exact learning rates
    lr_actor: float = 3e-4
    lr_critic: float = 1e-5       # paper uses 10^-5 for critic

    gamma: float = 0.99
    K_epochs: int = 80
    eps_clip: float = 0.2

    # Training duration
    max_training_timesteps: int = int(2e6)

    # Update every 100 episodes (paper Section 4.1: batch size 290, 100 episodes)
    update_every_episodes: int = 100

    log_freq: int = 100
    save_model_freq: int = int(1e5)
    random_seed: int = 0

    # Paper-exact topology: Chimera 45x45 K4,4
    topo_row: int = 45
    topo_col: int = 45
    bipart_cell: int = 4

    # Diverse training set (195 graphs across 25 structural families)
    # lg_num_nodes is the MAX node count across all training graphs —
    # used to set action_dim. The actual graphs vary in size.
    # manifest.pkl (written by 01_generate_training_data.py) sets
    # training_size automatically at runtime.
    lg_num_nodes: int = 120      # max nodes in diverse training set
    lg_degree: int = 5           # only used if mode=0 (auto-generate), not used here
    training_size: int = 195     # overridden by manifest.pkl at runtime

    # Paths
    training_data_dir: str = "training_data"
    orderlist_path: str = "orderlist.pkl"
    checkpoint_dir: str = "checkpoints"
    atom_binary: str = "../charme-rl/ours/atom_system"

    device: str = "cuda" if torch.cuda.is_available() else "cpu"


def load_training_data(cfg: TrainConfig):
    """Load pre-generated graphs and minorminer baselines.

    Reads training_size from manifest.pkl if present (generated by
    01_generate_training_data.py), so you don't need to manually update
    TrainConfig.training_size after generating a diverse training set.
    """
    data_dir = Path(cfg.training_data_dir)

    # Auto-detect training_size from manifest if available
    manifest_path = data_dir / "manifest.pkl"
    if manifest_path.exists():
        with open(manifest_path, "rb") as f:
            manifest = pickle.load(f)
        actual_size = manifest["total_graphs"]
        if actual_size != cfg.training_size:
            print(f"  INFO: manifest.pkl reports {actual_size} graphs, "
                  f"overriding TrainConfig.training_size={cfg.training_size}")
            cfg.training_size = actual_size

    graph_list = []
    for i in range(cfg.training_size):
        path = data_dir / f"graph_{i}.txt"
        if not path.exists():
            raise FileNotFoundError(
                f"Missing {path}\n"
                "Run first: python scripts/01_generate_training_data.py"
            )
        G = nx.read_edgelist(str(path), nodetype=int)
        G = nx.convert_node_labels_to_integers(G)
        graph_list.append(G)

    mm_path = data_dir / "minorminer_results.pth"
    if not mm_path.exists():
        raise FileNotFoundError(
            f"Missing {mm_path}\n"
            "Run first: python scripts/01_generate_training_data.py"
        )
    with open(mm_path, "rb") as f:
        minorminer_list = pickle.load(f)

    return graph_list, minorminer_list


def check_orderlist(cfg: TrainConfig):
    if not Path(cfg.orderlist_path).exists():
        raise FileNotFoundError(
            f"Missing {cfg.orderlist_path}\n"
            "Run first: python scripts/02_generate_orderlist.py\n"
            "Quick version: python scripts/02_generate_orderlist.py "
            "--sampling_limit 100 --exploration_limit 1000"
        )


def main(cfg: TrainConfig):
    device = torch.device(cfg.device)
    torch.manual_seed(cfg.random_seed)

    print("=" * 60)
    print("CHARME Training — Paper-Exact Configuration")
    print("=" * 60)
    print(f"  Hardware:    Chimera({cfg.topo_row},{cfg.topo_col},{cfg.bipart_cell})")
    print(f"  Graphs:      {cfg.training_size} x BA(n={cfg.lg_num_nodes}, d={cfg.lg_degree})")
    print(f"  lr_actor:    {cfg.lr_actor}")
    print(f"  lr_critic:   {cfg.lr_critic}")
    print(f"  K_epochs:    {cfg.K_epochs}")
    print(f"  Max steps:   {cfg.max_training_timesteps:,}")
    print(f"  Device:      {device}")
    if device.type == "cuda":
        print(f"  GPU:         {torch.cuda.get_device_name(0)}")
    print("=" * 60)

    # ── Load data ──────────────────────────────────────────────────────────────
    print("\nLoading training data...")
    graph_list, minorminer_list = load_training_data(cfg)
    check_orderlist(cfg)
    print(f"  Loaded {len(graph_list)} graphs, orderlist OK")

    # ── Build environment ──────────────────────────────────────────────────────
    # FIX: pass orderlist_path and atom_binary_path as constructor args
    env = MinorEmbeddingEnv(
        topo_row=cfg.topo_row,
        topo_col=cfg.topo_col,
        bipart_cell=cfg.bipart_cell,
        goal_dim=1,
        num_nodes=cfg.lg_num_nodes,
        n_state=1,
        seed=cfg.random_seed,
        degree=cfg.lg_degree,
        training_size=cfg.training_size,
        orderlist_path=cfg.orderlist_path,
        atom_binary_path=cfg.atom_binary,
        mode=1,   # mode=1: don't auto-generate graphs, we load them below
    )
    env.load_graph(graph_list, minorminer_list)

    # ── Build PPO agent ────────────────────────────────────────────────────────
    action_dim = cfg.lg_num_nodes
    state_dim = 0  # models read tensors directly from env state dict

    ppo_agent = PPO(
        state_dim=state_dim,
        action_dim=action_dim,
        lr_actor=cfg.lr_actor,
        lr_critic=cfg.lr_critic,
        gamma=cfg.gamma,
        K_epochs=cfg.K_epochs,
        eps_clip=cfg.eps_clip,
        has_continuous_action_space=cfg.has_continuous_action_space,
        action_std_init=cfg.action_std,
        device=device,
    )

    os.makedirs(cfg.checkpoint_dir, exist_ok=True)

    # ── sigma: exploration weight (Section 3.1.2) ──────────────────────────────
    # Starts at 0, increases by 0.01 per policy update until [1-sigma] = 0
    sigma = 0.0

    # ── Training loop (authors' exact structure) ───────────────────────────────
    print("\nStarting training...\n")
    time_step = 0
    i_episode = 0
    nums_done = 0
    saved_res = []

    while time_step <= cfg.max_training_timesteps:

        # Authors' exact reset call
        state = env.reset(mode="batch_change_logical_graph")
        done = False
        current_ep_reward = 0
        count_step = 0

        minorminer_solution_embedding = env.minorminer

        while not done:
            time_step += 1
            count_step += 1

            # Authors' exact select_action call
            state, action, action_logprob, state_val = ppo_agent.select_action(
                state, env.mask, env.mask_connected
            )
            state = copy.deepcopy(env.state)
            reward, reward_distance, done = env.step(action.item())

            if done == -1:
                # Crash — authors' exact crash handling
                ppo_agent.buffer.clear_partial(count_step - 1)
                break

            for k in state.keys():
                if k != 'emb_dict':
                    state[k] = state[k].to(device)

            # Authors' exact buffer append
            ppo_agent.buffer.states['hw_attr'].append(state['hw_attr'])
            ppo_agent.buffer.states['emb_matrix'].append(state['emb_matrix'])
            ppo_agent.buffer.states['logical_index'].append(
                (env.training_index) % env.training_size
            )
            ppo_agent.buffer.actions.append(action)
            ppo_agent.buffer.logprobs.append(action_logprob)
            ppo_agent.buffer.state_values.append(state_val)
            ppo_agent.buffer.rewards.append(reward)
            # Scale reward_distance by [1-sigma] per Equation 9
            ppo_agent.buffer.rewards_distance.append((1 - sigma) * reward_distance)
            ppo_agent.buffer.is_terminals.append(done)

            current_ep_reward += reward

            if done == 1:
                nums_done += 1
                saved_res.append([
                    len(minorminer_solution_embedding),
                    len(env.embedding)
                ])

        i_episode += 1

        # ── Policy update every 100 episodes (paper Section 4.1) ──────────────
        # FIX: update() called with (env) instead of broken (env, alpha, buffer_index_list)
        if i_episode % cfg.update_every_episodes == 0 and ppo_agent.buffer.len() > 0:
            ppo_agent.update(env)
            # FIX: sigma scheduling — increases by 0.01 per update
            sigma = min(1.0, sigma + 0.01)

        # ── Logging ────────────────────────────────────────────────────────────
        if i_episode % cfg.log_freq == 0:
            recent = saved_res[-cfg.log_freq:] if len(saved_res) >= cfg.log_freq else saved_res
            if recent:
                avg_mm = sum(r[0] for r in recent) / len(recent)
                avg_rl = sum(r[1] for r in recent) / len(recent)
                print(
                    f"Episode {i_episode:>6} | "
                    f"Timestep {time_step:>9,} | "
                    f"Reward {current_ep_reward:>8.2f} | "
                    f"RL qubits {avg_rl:>7.1f} | "
                    f"MM qubits {avg_mm:>7.1f} | "
                    f"sigma {sigma:.2f}"
                )
            else:
                print(
                    f"Episode {i_episode:>6} | "
                    f"Timestep {time_step:>9,} | "
                    f"Reward {current_ep_reward:>8.2f}"
                )

        # ── Checkpoint ─────────────────────────────────────────────────────────
        if time_step % cfg.save_model_freq == 0:
            os.makedirs(cfg.checkpoint_dir, exist_ok=True)
            ckpt = os.path.join(cfg.checkpoint_dir, f"ppo_{cfg.env_name}_{time_step}.pth")
            ppo_agent.save(ckpt)
            print(f"  Saved: {ckpt}")

    # Final save
    final = os.path.join(cfg.checkpoint_dir, f"ppo_{cfg.env_name}_final.pth")
    ppo_agent.save(final)
    print(f"\nTraining complete. Final checkpoint: {final}")
    print(f"\nTo use in QEBench:")
    print(f"  copy {final} ..\\quantum_embedding_benchmark\\algorithms\\charme\\checkpoints\\charme_trained.pth")


if __name__ == "__main__":
    p = argparse.ArgumentParser()
    p.add_argument("--atom_binary", type=str, default=None)
    p.add_argument("--device", type=str, default=None)
    p.add_argument("--orderlist_path", type=str, default=None)
    p.add_argument("--training_data_dir", type=str, default=None)
    p.add_argument("--topo_row", type=int, default=None)
    p.add_argument("--topo_col", type=int, default=None)
    p.add_argument("--lg_num_nodes", type=int, default=None)
    p.add_argument("--lg_degree", type=int, default=None)
    p.add_argument("--training_size", type=int, default=None)
    args = p.parse_args()

    cfg = TrainConfig()
    if args.atom_binary:   cfg.atom_binary = args.atom_binary
    if args.device:        cfg.device = args.device
    if args.orderlist_path: cfg.orderlist_path = args.orderlist_path
    if args.training_data_dir: cfg.training_data_dir = args.training_data_dir
    if args.topo_row:      cfg.topo_row = args.topo_row
    if args.topo_col:      cfg.topo_col = args.topo_col
    if args.lg_num_nodes:  cfg.lg_num_nodes = args.lg_num_nodes
    if args.lg_degree:     cfg.lg_degree = args.lg_degree
    if args.training_size: cfg.training_size = args.training_size

    main(cfg)
